INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1001, 2, 1.4, "お！\nあそこに困ってそうな人発見！", "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 0, 1, 1, 0, "春咲 ひより", "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1002, 2, 1.4, "大切な人を\n守れるようになりたい…って", "わ、わたし、\nなに言ってるんだろ\nあはは…", 0, 1, 1, 0, "草野 優衣", "みんなみたいに\nわたしも強くならなきゃ", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1003, 2, 1.4, "キミに必要な集中力と感性が", "少しは磨かれると思いますよ。", 0, 1, 1, 0, "士条 怜", "フェンシングを始めてみては？", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1004, 2, 1.5, "今日はなにして遊ぶ？", "みそぎはねぇ、\nかくれんぼやりたい！", 0, 1, 1, 0, "穂高 みそぎ", "ねぇ、にいちゃん！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1006, 2, 1.4, "ねぇ…", "私といっしょに…\nいかない？", 0, 1, 1, 0, "風宮 あかり", "風宮あかりです", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1007, 2, 1.5, "プリンたべたいのー", "食べ物の恨みは怖いのー", 0, 1, 1, 0, "出雲 宮子", "出雲宮子なのー", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1008, 2, 1.4, "キミもボクの美貌に\n吸い寄せられたんだね。", "いいよ。\n見られることは運命さ…", 0, 1, 1, 0, "虹村 雪", "ボクは虹村雪。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1009, 2, 1.4, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", "人呼んで「疾風の冥姫」!!", 0, 1, 1, 0, "柊杏奈", "フッ…聞いて後悔するがいい！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1010, 2, 1.5, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", "ほんまおおきにやわ～♪", 0, 1, 1, 0, "姫宮 真歩", "マホマホ王国のプリンセス、\nまほ姫どす", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1011, 2, 1.4, "生き別れたお兄ちゃんを探して\n三千世界！", "ここで会ったが\n100年目～！", 0, 1, 1, 0, "衣之咲 璃乃", "衣之咲璃乃です！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1012, 2, 1.4, "ち、超能力って…\n何のことかな～？", "…って、お願い！\n誰にも言わないでおいて～！", 0, 1, 1, 0, "柏崎 初音", "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1016, 2, 1.4, "一応カリスマ読モJKやってまっす！", "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 0, 1, 1, 0, "美波 鈴奈", "ちょす！\n美波鈴奈だよ～♪", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1017, 2, 1.4, "東京は遊園地みたいなところさー", "でも、沖縄もとってもいいとこさー", 0, 1, 1, 0, "喜屋武 香織", "はいたーい。\n喜屋武香織さー。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1018, 2, 1.4, "先生って呼ばれるのは\nくすぐったいから", "イオちゃんって呼んでね。", 0, 1, 1, 0, "支倉 伊緒", "支倉伊緒です。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1020, 2, 1.5, "あ！/\お兄ちゃ～ん\nまってよ～", "ミミをおいてかないでぇ～", 0, 1, 1, 0, "茜 ミミ", "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1021, 2, 1.5, "あの……\nふぇ……", "ふぇぇぇぇぇん……", 0, 1, 1, 0, "栗林 くるみ", "あ…あの…えっと…\n栗…林…くるみ…です……", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1022, 2, 1.4, "こんな私に貴重な時間を\n割いていただき、", "なんてありがとうございます！", 0, 1, 1, 0, "風宮 より", "風宮よりです。\nあああああ！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1023, 2, 1.5, "おにいちゃんどこいくの？\nえ？", "私こっち行きたいー\nね、早く早くー", 0, 1, 1, 0, "北条 綾音", "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1025, 2, 1.4, "ふ、不束者ですが\nどうぞ末永く…って、", "これて何か違う…\nあああすみません！", 0, 1, 1, 0, "天野 すずめ", "わっ…わっ…私、\n天野すずめといいます！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1027, 2, 1.4, "あなたは…運命の……\n伴侶……", "離しませんわ………\n絶対に…!!", 0, 1, 1, 0, "倉石 恵理子", "……クスクス…私は\n…倉石恵理子……", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1028, 2, 1.4, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", "…そうでしょ？？", 0, 1, 1, 0, "佐々木 咲恋", "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1029, 2, 1.4, "ぇっと…\nキミ、私のこと知らないの?!", "あはは、\n私もまだまだだなぁ～", 0, 1, 1, 0, "桜井 望", "桜井望だよ！\nよろしくねっ", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1030, 2, 1.4, "初めまして、\n私はニノン・ジュベール申すデス！", "ショーグン、\nワタシと一緒に天下統一デース！", 0, 1, 1, 0, "ニノン・ジュベール", "デケデケデンっ！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1031, 2, 1.4, "でもって私の隣にいるのが……\nえ、見えない？", "おかしいですね……", 0, 1, 1, 0, "上喜 しのぶ", "上喜しのぶです。\n手元のドクロが父です。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1033, 2, 1.5, "けんども\nそれには足りないモンが…", "そう、\nオラのボケに突っ込める相方が…！", 0, 1, 1, 0, "野戸まひる", "目指すはビッグな\nお笑い芸人だっぺ！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1034, 2, 1.4, "ちょっと緊張しちゃって…", "ちょ\nちょっと一杯飲んできます…！", 0, 1, 1, 0, "綾瀬 ゆかり", "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1036, 2, 1.5, "知らない人とは話しちゃいけないので", "これ以上お話しすることは…\nないです！", 0, 1, 1, 0, "氷川 鏡華", "氷川鏡華…です", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1038, 2, 1.4, "……あ、アラーム。", "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 0, 1, 1, 0, "柏崎 栞", "柏崎…栞です。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1040, 2, 1.4, "私、一人も友達がいなくて……", "野に咲く花が、\n唯一の話相手です。", 0, 1, 1, 0, "双葉 碧", "ふ、双葉碧です。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1042, 2, 1.4, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", "そう思っています。", 0, 1, 1, 0, "三角 千歌", "三角千歌です。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1043, 2, 1.4, "あぁ？\nお前のそいつの仲間か？", "う、疑ってすまなかったな…", 0, 1, 1, 0, "安芸 真琴", "安芸真琴だ。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1044, 2, 1.4, "生けとし生ける全ての者よ！", "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 0, 1, 1, 0, "イリヤ・オーンスタイン", "わらわこそは夜を総べる者！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1045, 2, 1.4, "ぐふふふふ……はっ！", "ｌク、クウカに何かご用ですか!?", 0, 1, 1, 0, "遠見 空花", "そこで騎士は妖精を乱暴に……", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1046, 2, 1.4, "自由気ままで♪\n寝て遊んで、食べてケンカして…", "う～ん…\n猫ってホントに最高にゃ～♪", 0, 1, 1, 0, "宮坂たまき", "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1048, 2, 1.4, "それでは早速クエストに…", "…と思ったら\nバイトの時間だ！\nまたあとでね！", 0, 1, 1, 0, "大神 美冬", "大神美冬よ！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1049, 2, 1.4, "クエストもバトルも\n掃除も洗濯も", "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 0, 1, 1, 0, "星野静流", "星野静流だよ！", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1050, 2, 1.5, "見ての通りの\nセクシー美少女で", "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 0, 1, 1, 0, "玉泉美咲", "アタシは玉泉美咲。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1052, 2, 1.4, "？？？？", "？？？？", 0, 1, 1, 0, "リマ", "？？？", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1053, 2, 1.5, "菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", 0, 1, 1, 0, "モニカ・ヴァイスヴィント", "モニカ・ヴァイスヴィントだ。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1058, 2, 1.5, "菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", 0, 1, 1, 0, "ペコリーヌ", "モニカ・ヴァイスヴィントだ。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1059, 2, 1.5, "菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", 0, 1, 1, 0, "コッコロ", "モニカ・ヴァイスヴィントだ。", 0, 1, 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 1060, 2, 1.5, "菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", 0, 1, 1, 0, "キャル", "モニカ・ヴァイスヴィントだ。", 0, 1, 0);
